async function sendCommand(target: string, power: string): Promise<void> {
  if (!target || !power) throw new Error('Missing fields');
  if (power === '0') throw new Error('Power cannot be zero');
}

export class SubmitFormComponent {
  form = { target: '', power: '', get valid() { return !!this.target && !!this.power; }, get invalid() { return !this.valid; } };
  loading = false;
  error = '';
  navigated = false;

  async submit(): Promise<void> {
    if (this.form.invalid) return;
    this.loading = true;
    try {
      await sendCommand(this.form.target, this.form.power);
      this.navigated = true;
    } catch (err) {
      this.error = String(err);
    } finally {
      this.loading = false;
    }
  }
}

