let callId = 0;
async function search(query: string): Promise<string[]> {
  callId++;
  const id = callId;
  const delay = id === 1 ? 80 : 10;  // first call is slow
  await new Promise(r => setTimeout(r, delay));
  return id === 1 ? ['stale-result'] : ['fresh-result'];
}

export class SearchComponent {
  results: string[] = [];
  // Bug: no request ID tracking — stale results can overwrite fresh ones

  async runSearch(query: string): Promise<void> {
    const data = await search(query);
    this.results = data;  // Bug: no check if this is still the latest request
  }
}

